const fs = require('fs');
const path = require('path');

const DATA_FILE = path.join(__dirname, 'data.json');

function readData() {
  if (!fs.existsSync(DATA_FILE)) {
    fs.writeFileSync(DATA_FILE, JSON.stringify([]), 'utf8');
  }
  try {
    const raw = fs.readFileSync(DATA_FILE, 'utf8');
    return JSON.parse(raw);
  } catch (e) {
    return [];
  }
}

function writeData(entries) {
  fs.writeFileSync(DATA_FILE, JSON.stringify(entries, null, 2), 'utf8');
}

function findByCode(code) {
  const entries = readData();
  return entries.find((e) => e.shortCode === code) || null;
}

function findAll() {
  return readData();
}

function create({ shortCode, originalUrl, expiresAt }) {
  const entries = readData();
  const entry = {
    shortCode,
    originalUrl,
    clicks: 0,
    createdAt: new Date().toISOString(),
    expiresAt: expiresAt || null,
  };
  entries.push(entry);
  writeData(entries);
  return entry;
}

function incrementClick(code) {
  const entries = readData();
  const entry = entries.find((e) => e.shortCode === code);
  if (entry) {
    entry.clicks += 1;
    writeData(entries);
  }
}

function isCodeTaken(code) {
  const entries = readData();
  return entries.some((e) => e.shortCode === code);
}

function deleteExpired() {
  const entries = readData();
  const now = new Date();
  const active = entries.filter((e) => {
    if (!e.expiresAt) return true;
    return new Date(e.expiresAt) > now;
  });
  writeData(active);
}

module.exports = {
  findByCode,
  findAll,
  create,
  incrementClick,
  isCodeTaken,
  deleteExpired,
};

const express = require('express');
const { nanoid } = require('nanoid');
const db = require('../db');

const router = express.Router();

// POST /api/shorten
router.post('/shorten', (req, res) => {
  const { originalUrl, customCode, expiresInDays } = req.body;

  if (!originalUrl) {
    return res.status(400).json({ error: 'originalUrl is required' });
  }

  const shortCode = customCode || nanoid(7);

  if (customCode && db.isCodeTaken(customCode)) {
    return res.status(409).json({ error: 'Custom code already in use' });
  }

  let expiresAt = null;
  if (expiresInDays) {
    const date = new Date();
    date.setDate(date.getDate() + Number(expiresInDays));
    expiresAt = date.toISOString();
  }

  const entry = db.create({ shortCode, originalUrl, expiresAt });
  const shortUrl = `${req.protocol}://${req.get('host')}/${shortCode}`;

  return res.status(201).json({
    shortCode: entry.shortCode,
    shortUrl,
    originalUrl: entry.originalUrl,
    expiresAt: entry.expiresAt,
  });
});

// GET /api/urls
router.get('/urls', (req, res) => {
  const entries = db.findAll();
  return res.json(entries);
});

// GET /api/urls/:code/stats
router.get('/urls/:code/stats', (req, res) => {
  const entry = db.findByCode(req.params.code);
  if (!entry) {
    return res.status(404).json({ error: 'Short code not found' });
  }
  return res.json({
    shortCode: entry.shortCode,
    originalUrl: entry.originalUrl,
    clicks: entry.clicks,
    createdAt: entry.createdAt,
    expiresAt: entry.expiresAt,
  });
});

module.exports = router;

const express = require('express');
const path = require('path');
const db = require('./db');
const urlsRouter = require('./routes/urls');

const app = express();
const PORT = process.env.PORT || 3000;

// Middleware
app.use(express.json());
app.use(express.static(path.join(__dirname, 'public')));

// API routes
app.use('/api', urlsRouter);

// GET /:code - redirect handler
app.get('/:code', (req, res) => {
  const { code } = req.params;
  const entry = db.findByCode(code);

  if (!entry) {
    return res.status(404).json({ error: 'Short URL not found' });
  }

  if (entry.expiresAt && new Date(entry.expiresAt) <= new Date()) {
    return res.status(404).json({ error: 'Short URL has expired' });
  }

  db.incrementClick(code);
  return res.redirect(301, entry.originalUrl);
});

// Start server
app.listen(PORT, () => {
  console.log(`Server running on port ${PORT}`);
});

module.exports = app;
